  ('dietitian-moex-07704', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '近年來的國民營養健康狀況調查（NAHSIT）中，那一次調查並未收集骨密度之檢測資料？', '["NAHSIT 1993-1996", "NAHSIT 1999-2000", "NAHSIT 2001-2002", "NAHSIT 2005-2008"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07705', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在臺灣地區老人營養變遷狀況調查（1999-2000）中，下列有關體位與慢性疾病的敘述，何者正確？', '["老人女性血脂狀況優於男性", "老人中央肥胖之盛行率呈現男性＞女性", "老人高血壓盛行率呈現男性＞女性", "超過一半的糖尿病老人有體重過重或肥胖的現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07706', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據學童國民營養健康狀況變遷調查（2001-2002）結果，有關學童營養素的主要食物來源，下列何者錯 誤？', '["提供醣類最主要的食物來源，為米類及其製品與冰飲料", "提供脂質最主要的食物來源，為家畜製品與堅果類", "提供鈣最主要的食物來源，為乳品與深綠色蔬菜", "提供鎂最主要的食物來源，為米類製品與乳品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07707', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據世界衛生組織的定義，肥胖是指身體質量指數（BMI）為何？', '["≧24", "≧25", "≧27", "≧30"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07708', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '美國飲食指標指導委員會（Dietary Guidelines Advisory Committee）建議，反式脂肪酸的攝取應小於總熱 量的：', '["1%", "2%", "3%", "4%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07709', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於流行病學常用專業名詞之敘述，下列何者正確？', '["發生率（incidence rate）＝新病例數∕平均人口數", "盛行率（prevalence rate）＝一段期間內的所有現存病例數∕得該病的人數", "死亡比（death or mortality ratio）＝得病死亡的人數∕得該病的人數", "死亡率（death or mortality rate）＝得病死亡的人數∕全體人口數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "45a1feb13276", "answer_pdf_sha1": "606fad96c6e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07710', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關食物代換表之敘述，何者錯誤？', '["是指將一些相似營養價值的定量食物歸於一類，用於飲食計畫中互相取代", "靈活應用食物代換表可使飲食富於變化", "飲食中1碗200克的白飯其營養成分相當於100克白土司", "食物代換表中吃乳酪一片相當於喝2杯牛奶"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "907fc579dde6", "answer_pdf_sha1": "b16af57e26e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07711', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '煮白米飯時，1杯米需加1杯水，若煮2台斤的米時，則需加多少杯水？', '["5杯", "6杯", "10杯", "12杯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "907fc579dde6", "answer_pdf_sha1": "b16af57e26e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07712', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依照「學校午餐內容及營養素基準」所訂的午餐食物種類與食物內容中，下列何者錯誤？', '["奶類每天至少1份", "其他非主食的五穀根莖類最多1份", "主食類午餐基準3~4份", "蛋豆魚肉類2~2.5份"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "907fc579dde6", "answer_pdf_sha1": "b16af57e26e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07713', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依據行政院衛生署所訂定的國人膳食營養素參考攝取量（DRIs），孕婦於第一至第三期皆不需額外攝取 下列那些營養素？', '["蛋白質、磷、鐵", "鈣、磷、氟", "鈣、維生素A、鐵", "氟、碘、鎂"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "907fc579dde6", "answer_pdf_sha1": "b16af57e26e3", "source_family": "moex-gov-tw", "moex": {"exam_code": "100140", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第二次專技中醫、營養、心理、醫事人員、醫師分試、100年法醫、語言治療、聽力、牙體技術考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
